var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부탁드리겠습니다. 버넷 요원.","JPN":"お願いします。エージェント・バーネット。","ENG":"Please, Agent Burnett.","TWN":"拜託你了，伯內特特工。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"부디 저에게 그자의 이름을…… 한 번 더 말씀해주시겠습니까?","JPN":"どうか私に彼の名前を……もう一度言ってくださいませんか。","ENG":"Will you say his name... one more time?","TWN":"能再告訴我一次……他的名字嗎？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"저의 오랜……. 친우의 이름을…….","JPN":"私の……古き親友の名前を……","ENG":"The name... of my old friend…","TWN":"我的……老朋友的名字……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"모건이야. 새디어스 모건.","JPN":"モーガンだ。タデウス・モーガン。","ENG":"Morgan. Thaddeus Morgan.","TWN":"是摩根，薩迪烏斯·摩根。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"기억해 두라고, 집사 할배.","JPN":"覚えておけよ、執事のジジイ。","ENG":"Keep that in mind, old chap.","TWN":"記住了，管家老頭。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"모건, 모건……. 새디어스 모건.","JPN":"モーガン、モーガン……タデウス・モーガン。","ENG":"Morgan, Morgan... Thaddeus Morgan.","TWN":"摩根，摩根……薩迪烏斯·摩根。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇군요. 그런 이름이었던 것 같습니다. ","JPN":"そうですね。そんな名前だった気がします。 ","ENG":"I see. Yes, I think it was that name.","TWN":"原來如此，好像就是那個名字。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"감사를 전합니다. 버넷 군.","JPN":"感謝します、バーネット君。","ENG":"I am grateful, Burnett.","TWN":"謝謝你，伯內特。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그 친구가 이곳에 이름을 남길 수 있도록 기억해 주어서.","JPN":"彼がここに名前を刻むことができるように、覚えていてくださって。","ENG":"For your remembering his name so that he can be remembered.","TWN":"謝謝你還記得那個名字，才得以讓那個老朋友在這裡留名。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"새디어스 모건이 남긴 의지를 이어주어서.","JPN":"タデウス・モーガンが残した意志を受け継いでくださって。","ENG":"For carrying on the will of Thaddeus Morgan.","TWN":"謝謝你繼承了薩迪烏斯·摩根的遺志。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"……아가씨, 제가 잠시 자리를 비워도 괜찮겠습니까?","JPN":"……お嬢様、しばらく席を外してもよろしいでしょうか。","ENG":"...My lady. May I be excused for a moment?","TWN":"……小姐，你介意我離開一會兒嗎？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"잠시 오랜 친우의 묘비에 추모를 남기고 오겠습니다.","JPN":"親友の墓碑で、弔いの言葉を残して来ます。","ENG":"I would like to pay my respects to an old friend of mine.","TWN":"我想去老朋友的墓碑追悼一下。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론이에요, 라이언.","JPN":"もちろんですわ、ライアン。","ENG":"Of course, Ryan.","TWN":"當然不介意，瑞安。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"끄윽, 미안하네. 내가 같이 갔었어야 했는데……!","JPN":"うぐっ、すまない。私がついていくべきだったのに……！","ENG":"*Sob.* I'm sorry. I should've been there with you...!","TWN":"咳嗚，對不起。我應該和你一起去的……！"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 자네를 잡아주었어야 했는데……!","JPN":"私が君を止めるべきだったのに……！","ENG":"I should've been there to stand by you...!","TWN":"我本該拉你一把的……！"},"stage":{"bg":"TOMB","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"너는 괜찮냐?","JPN":"お前は大丈夫か？","ENG":"Are you okay?","TWN":"喂，你……沒事吧？"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"괜찮냐고 물어보신다면, 괜찮지 않습니다만.","JPN":"大丈夫かとおっしゃると、そんなことはありませんが。","ENG":"Well, I am not exactly \\"okay.\\"","TWN":"既然你都這麼問了，那麼我肯定是有事。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관장은 남들 앞에서 함부로 감정을 드러내면 안 됩니다.","JPN":"機関長は人前で迂闊に感情を表してはいけません。","ENG":"But the Chief should not be vulnerable in front of others.","TWN":"不過機關長不能在他人面前隨意表露自己的感情。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"저는 그런 위치에 있는 사람이니까요.","JPN":"私はそういう立場にいる身ですので。","ENG":"That is the position I am in.","TWN":"因為我的地位不允許我那麼做。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그러니 당장의 슬픔보다는 미래를 위해 분노를 곱씹는 편이 낫습니다.","JPN":"ですから、目の前の悲しみより、未来のための怒りを噛み締めるようにしています。","ENG":"It is better to harness anger for the future rather than sorrow for the present.","TWN":"所以比起眼前的悲傷，為了未來，還不如反復體味那股憤怒。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시는 이런 감정을 느낄 필요 없도록.","JPN":"二度とこんな感情を味わうことがないように。","ENG":"So that we never feel this way again.","TWN":"為了以後，再也不會感受到這種感覺。"},"stage":{"bg":"TOMB","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그러냐? 너도 힘들겠네.","JPN":"そうか、お前も大変だな。","ENG":"Is that so? Must be tough.","TWN":"是嗎？你應該也很累吧。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그럼, 남들이 보지 않는 곳에서는 충분히 울어 둬.","JPN":"じゃあ、人がいないところで思う存分泣いておけよ。","ENG":"Then, cry your heart out when nobody's around.","TWN":"那麼，在別人看不見的地方哭個夠吧。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그렇지 않으면…… 망가진다.","JPN":"じゃないと……心が壊れるぞ。","ENG":"Or else... You're gonna break.","TWN":"不然……你會憋壞的。"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그래서 앞으로 어떻게 할 거야?","JPN":"で、これからどうする？","ENG":"So, what are you going to do now?","TWN":"那麼，接下來我們要怎麼辦?"},"stage":{"bg":"TOMB","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};